from ..helpers.add_middleware import FlaskWithMiddleware as Flask
from ..helpers.env_vars import get_bool_env
from ..extensions import db, migrate, setup_write_serialization
from ..routes import init_app
from .. import models  # noqa: F401
from .merger_ci import init_app as init_merger_cli, post_treatment
import sys
import os
import threading
from datetime import datetime, timezone
import signal

MAX_SCRIPT_STEPS = 8
SCAN_FILE = "/scan/status.txt"
DEFAULT_DB_URI = "sqlite:////cache/vulnscout/vulnscout.db"


def _launch_enrichment(app):
    """Spawn background threads for EPSS and NVD enrichment.

    Each runs in its own thread so they execute in parallel and neither
    blocks Flask request handlers (WAL journal mode allows concurrent reads).
    """
    def _enrich_epss():
        with app.app_context():
            # Disable autoflush: without this, every SELECT triggers a flush
            # which acquires the write-lock and holds it across the slow HTTP
            # calls until the next explicit commit().  With autoflush=False
            # the lock is only held during commit() itself (milliseconds).
            db.session.autoflush = False
            try:
                from ..controllers.packages import PackagesController
                from ..controllers.vulnerabilities import VulnerabilitiesController
                pkgCtrl = PackagesController()
                vulnCtrl = VulnerabilitiesController(pkgCtrl)
                post_treatment({"vulnerabilities": vulnCtrl, "packages": pkgCtrl})
            except Exception as e:
                print(f"[enrichment/epss] {e}", flush=True)

    def _enrich_nvd():
        with app.app_context():
            db.session.autoflush = False
            try:
                from ..controllers.packages import PackagesController
                from ..controllers.vulnerabilities import VulnerabilitiesController
                pkgCtrl = PackagesController()
                vulnCtrl = VulnerabilitiesController(pkgCtrl)
                vulnCtrl.fetch_nvd_data()
            except Exception as e:
                print(f"[enrichment/nvd] {e}", flush=True)

    threading.Thread(target=_enrich_epss, name="enrichment-epss", daemon=True).start()
    threading.Thread(target=_enrich_nvd, name="enrichment-nvd", daemon=True).start()


def create_app():
    app = Flask(__name__, static_folder="../static")
    app.config.from_prefixed_env()
    app._INT_SCAN_FINISHED = False
    if "SCAN_FILE" not in app.config:
        app.config["SCAN_FILE"] = SCAN_FILE
    app.config["SCAN_DATE"] = "unknown date"

    if "SQLALCHEMY_DATABASE_URI" not in app.config:
        app.config["SQLALCHEMY_DATABASE_URI"] = DEFAULT_DB_URI

    # Set the busy-timeout at the sqlite3.connect() level so every connection
    # is guaranteed to wait up to 30 s for the write lock before raising
    # "database is locked".  This is more reliable than PRAGMA busy_timeout
    # set after the connection is opened.
    db_uri = app.config.get("SQLALCHEMY_DATABASE_URI", "")
    if db_uri.startswith("sqlite"):
        engine_opts = app.config.setdefault("SQLALCHEMY_ENGINE_OPTIONS", {})
        connect_args = engine_opts.setdefault("connect_args", {})
        connect_args.setdefault("timeout", 30)

    db.init_app(app)
    _migrations_dir = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), 'migrations')
    migrate.init_app(app, db, directory=_migrations_dir)

    # SQLite WAL mode: allows concurrent reads while the background enrichment
    # thread writes EPSS/NVD data.  Without WAL, SQLite's default DELETE journal
    # mode serialises all reads behind any active write transaction, blocking
    # every Flask request while the enrichment thread commits batches.
    # WAL is a persistent DB-level setting — one-time setup per database file.
    # PRAGMAs are SQLite-only; skip silently on other DB engines (e.g. MySQL).
    with app.app_context():
        if db.engine.dialect.name == "sqlite":
            try:
                db.session.execute(db.text("PRAGMA journal_mode=WAL"))
                db.session.execute(db.text("PRAGMA synchronous=NORMAL"))
                db.session.execute(db.text("PRAGMA busy_timeout=30000"))
                db.session.commit()
            except Exception:
                pass
            # Serialise write transactions across threads so that
            # concurrent enrichment / request commits never trigger
            # "database is locked".
            setup_write_serialization(db.session)

    # Ensure every new SQLite connection inherits the busy timeout so that
    # concurrent writes from background threads don't immediately fail.
    try:
        from sqlalchemy import event as _sa_event

        @_sa_event.listens_for(db.engine, "connect")
        def _set_sqlite_busy_timeout(dbapi_conn, _rec):
            dbapi_conn.execute("PRAGMA busy_timeout=30000")
    except Exception:
        pass

    def is_scan_finished():
        if app._INT_SCAN_FINISHED:
            return True
        with open(app.config["SCAN_FILE"], "r") as f:
            if "__END_OF_SCAN_SCRIPT__" in f.read():
                if not get_bool_env('DEBUG_SKIP_SCAN'):
                    app.config["SCAN_DATE"] = datetime.now(timezone.utc).strftime("%Y-%m-%d at %H:%M (UTC)")
                app._INT_SCAN_FINISHED = True
                if not app.config.get("TESTING"):
                    _launch_enrichment(app)
                return True
        return False

    @app.after_request
    def add_CORS_header(response):
        response.headers["Access-Control-Allow-Origin"] = "*"
        response.headers["Access-Control-Allow-Methods"] = "GET, POST, PUT, DELETE, PATCH, OPTIONS"
        response.headers["Access-Control-Allow-Headers"] = "Content-Type"
        return response

    @app.route("/<path:path>", methods=["OPTIONS"])
    def allow_OPTION_CORS(path):
        return "OK", 200

    # provide version info
    @app.route("/api/version")
    def version():
        return {"version": os.getenv("VULNSCOUT_VERSION", "unknown")}

    # bypass fail_scan middleware because it's before
    @app.route("/api/scan/status")
    def loading():
        with open(app.config["SCAN_FILE"], "r") as f:
            text = f.read()
            if "__END_OF_SCAN_SCRIPT__" in text:
                return {
                    "status": "done",
                    "maxsteps": MAX_SCRIPT_STEPS,
                    "step": MAX_SCRIPT_STEPS,
                    "message": "Scan complete"
                }
            else:
                step = text.splitlines()[-1].split(" ")
                return {
                    "status": "running",
                    "maxsteps": MAX_SCRIPT_STEPS,
                    "step": int(step.pop(0)),
                    "message": " ".join(step)
                }

    @app.middleware("/api")
    def fail_scan_not_finished(*args, **kw):
        if not is_scan_finished():
            return {"error": "Scan not finished"}, 503

    init_app(app)
    init_merger_cli(app)
    return app


def stop_handler(signal, frame):
    print("Stopping Flask server")
    sys.exit(0)


signal.signal(signal.SIGINT, stop_handler)
